        public IEnumerable<String> JsonTranslator_Tuple(TypeSpec tp, String NamespaceName)
        {
            var SimpleName = tp.SimpleName(NamespaceName);
            var TypeString = GetTypeString(tp, NamespaceName);
            yield return "@staticmethod";
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "def "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "FromJson"))), "(j: Any) -> "), TypeString), ":"))
            {
                yield return _Line;
            }
            yield return "    if not isinstance(j, list):";
            yield return "        raise TypeError('Expected array')";
            yield return "    return [";
            {
                int k = 0;
                foreach (var t in tp.Tuple)
                {
                    if (k == tp.Tuple.Count - 1)
                    {
                        foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), t.SimpleName(NamespaceName)), "FromJson"))), "(j["), k), "])"))
                        {
                            yield return _Line == "" ? "" : "        " + _Line;
                        }
                    }
                    else
                    {
                        foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), t.SimpleName(NamespaceName)), "FromJson"))), "(j["), k), "]),"))
                        {
                            yield return _Line == "" ? "" : "        " + _Line;
                        }
                    }
                    k += 1;
                }
            }
            yield return "    ]";
            yield return "";
            yield return "@staticmethod";
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "def "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "ToJson"))), "(t: "), TypeString), ") -> Any:"))
            {
                yield return _Line;
            }
            yield return "    return [";
            {
                int k = 0;
                foreach (var t in tp.Tuple)
                {
                    if (k == tp.Tuple.Count - 1)
                    {
                        foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), t.SimpleName(NamespaceName)), "ToJson"))), "(t["), k), "])"))
                        {
                            yield return _Line == "" ? "" : "        " + _Line;
                        }
                    }
                    else
                    {
                        foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), t.SimpleName(NamespaceName)), "ToJson"))), "(t["), k), "]),"))
                        {
                            yield return _Line == "" ? "" : "        " + _Line;
                        }
                    }
                    k += 1;
                }
            }
            yield return "    ]";
        }
        public IEnumerable<String> JsonTranslator_Optional(TypeSpec o, TaggedUnionDef GenericOptionalType, String NamespaceName)
