            yield return "        return None";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "    return JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), ElementSimpleName), "FromJson"))), "(j[\"some\"])"))
            {
