            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "def "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "ToJson"))), "(o: "), TypeString), ") -> Any:"))
            {
                yield return _Line;
            }
            yield return "    if o is None:";
            yield return "        return {\"none\": {}}";
            foreach (var _Line in Combine(Combine(Combine(Begin(), "    return {\"some\": JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), ElementSimpleName), "ToJson"))), "(o)}"))
            {
