        public IEnumerable<String> JsonTranslator_Map(TypeSpec l, String NamespaceName)
        {
            var gp = l.GenericTypeSpec.ParameterValues;
            if (gp.Count != 2)
            {
                throw new ArgumentException();
            }
            var SimpleName = l.SimpleName(NamespaceName);
            var TypeString = GetTypeString(l, NamespaceName);
            var KeySimpleName = gp[0].SimpleName(NamespaceName);
            var ValueSimpleName = gp[1].SimpleName(NamespaceName);
            yield return "@staticmethod";
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "def "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "FromJson"))), "(j: Any) -> "), TypeString), ":"))
            {
                yield return _Line;
            }
            yield return "    if not isinstance(j, list):";
            yield return "        raise TypeError('Expected array')";
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "    return {JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), KeySimpleName), "FromJson"))), "(e[\"key\"]): JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), ValueSimpleName), "FromJson"))), "(e[\"value\"]) for e in j}"))
            {
                yield return _Line;
            }
            yield return "";
            yield return "@staticmethod";
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "def "), GetEscapedIdentifier(Combine(Combine(Begin(), SimpleName), "ToJson"))), "(o: "), TypeString), ") -> Any:"))
            {
                yield return _Line;
            }
            foreach (var _Line in Combine(Combine(Combine(Combine(Combine(Begin(), "    return [{\"key\": JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), KeySimpleName), "ToJson"))), "(k), \"value\": JsonTranslator."), GetEscapedIdentifier(Combine(Combine(Begin(), ValueSimpleName), "ToJson"))), "(v)} for k, v in o.items()]"))
            {
                yield return _Line;
            }
        }
